// Some portions generated by Co-Pilot
import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
import {
  fetchLatestAssets,
  fetchFeatureReleases,
  fetchReleaseNotes,
  fetchLatestReleaseName,
  fetchOperatingSystems,
  fetchArchitectures,
  fetchAttestations,
  fetchDownloadStats,
  fetchMarketplaceReleases,
} from "../adoptiumApi";

const { mockAdoptiumGet, mockMarketplaceGet } = vi.hoisted(() => ({
  mockAdoptiumGet: vi.fn(),
  mockMarketplaceGet: vi.fn(),
}));

vi.mock("openapi-fetch", () => ({
  default: vi.fn((options: { baseUrl: string }) => ({
    GET: options.baseUrl.includes("marketplace")
      ? mockMarketplaceGet
      : mockAdoptiumGet,
  })),
}));

afterEach(() => {
  vi.clearAllMocks();
});

// ---------------------------------------------------------------------------
// fetchLatestAssets
// ---------------------------------------------------------------------------
describe("fetchLatestAssets", () => {
  it("returns data on success", async () => {
    const mockData = [{ release_name: "jdk-21+35" }];
    mockAdoptiumGet.mockResolvedValue({ data: mockData, error: null });

    const result = await fetchLatestAssets(21);
    expect(result).toEqual(mockData);
    expect(mockAdoptiumGet).toHaveBeenCalledOnce();
  });

  it("returns empty array when data is null", async () => {
    mockAdoptiumGet.mockResolvedValue({ data: null, error: null });

    const result = await fetchLatestAssets(21);
    expect(result).toEqual([]);
  });

  it("throws on API error", async () => {
    mockAdoptiumGet.mockResolvedValue({
      data: null,
      error: { message: "not found" },
    });

    await expect(fetchLatestAssets(21)).rejects.toEqual({
      message: "not found",
    });
  });

  it("parses string version to number", async () => {
    mockAdoptiumGet.mockResolvedValue({ data: [], error: null });

    await fetchLatestAssets("17");
    const callArgs = mockAdoptiumGet.mock.calls[0][1];
    expect(callArgs.params.path.feature_version).toBe(17);
  });

  it("passes os and architecture query params", async () => {
    mockAdoptiumGet.mockResolvedValue({ data: [], error: null });

    await fetchLatestAssets(21, { os: "linux", architecture: "x64" });
    const callArgs = mockAdoptiumGet.mock.calls[0][1];
    expect(callArgs.params.query.os).toBe("linux");
    expect(callArgs.params.query.architecture).toBe("x64");
  });
});

// ---------------------------------------------------------------------------
// fetchFeatureReleases
// ---------------------------------------------------------------------------
describe("fetchFeatureReleases", () => {
  it("returns data and pagecount from header", async () => {
    const mockData = [{ release_name: "jdk-21+35" }];
    const mockHeaders = {
      get: vi.fn((key: string) => (key === "pagecount" ? "5" : null)),
    };
    mockAdoptiumGet.mockResolvedValue({
      data: mockData,
      error: null,
      response: { headers: mockHeaders },
    });

    const result = await fetchFeatureReleases(21, "ga");
    expect(result.data).toEqual(mockData);
    expect(result.pagecount).toBe(5);
  });

  it("falls back to PageCount header", async () => {
    const mockHeaders = {
      get: vi.fn((key: string) => (key === "PageCount" ? "3" : null)),
    };
    mockAdoptiumGet.mockResolvedValue({
      data: [],
      error: null,
      response: { headers: mockHeaders },
    });

    const result = await fetchFeatureReleases(21, "ga");
    expect(result.pagecount).toBe(3);
  });

  it("defaults pagecount to 0 when headers are absent", async () => {
    const mockHeaders = { get: vi.fn(() => null) };
    mockAdoptiumGet.mockResolvedValue({
      data: [],
      error: null,
      response: { headers: mockHeaders },
    });

    const result = await fetchFeatureReleases(21, "ga");
    expect(result.pagecount).toBe(0);
  });

  it("returns empty array when data is null", async () => {
    const mockHeaders = { get: vi.fn(() => null) };
    mockAdoptiumGet.mockResolvedValue({
      data: null,
      error: null,
      response: { headers: mockHeaders },
    });

    const result = await fetchFeatureReleases(21, "ga");
    expect(result.data).toEqual([]);
  });

  it("throws on API error", async () => {
    const mockHeaders = { get: vi.fn(() => null) };
    mockAdoptiumGet.mockResolvedValue({
      data: null,
      error: { message: "server error" },
      response: { headers: mockHeaders },
    });

    await expect(fetchFeatureReleases(21, "ga")).rejects.toEqual({
      message: "server error",
    });
  });
});

