// fetchLatestReleaseName
// ---------------------------------------------------------------------------
describe("fetchLatestReleaseName", () => {
  it("returns first release name on success", async () => {
    mockAdoptiumGet.mockResolvedValue({
      data: { releases: ["jdk-21.0.3+9"] },
      error: null,
    });

    const result = await fetchLatestReleaseName();
    expect(result).toBe("jdk-21.0.3+9");
  });

  it("returns null on API error", async () => {
    mockAdoptiumGet.mockResolvedValue({
      data: null,
      error: { message: "error" },
    });

    const result = await fetchLatestReleaseName();
    expect(result).toBeNull();
  });

  it("returns null when releases array is empty", async () => {
    mockAdoptiumGet.mockResolvedValue({ data: { releases: [] }, error: null });

    const result = await fetchLatestReleaseName();
    expect(result).toBeNull();
  });

  it("returns null when data has no releases property", async () => {
    mockAdoptiumGet.mockResolvedValue({ data: {}, error: null });

    const result = await fetchLatestReleaseName();
    expect(result).toBeNull();
  });

  it("returns null when request throws", async () => {
    mockAdoptiumGet.mockRejectedValue(new Error("network error"));

    const result = await fetchLatestReleaseName();
    expect(result).toBeNull();
  });
});

