// ---------------------------------------------------------------------------
describe("fetchOperatingSystems", () => {
  it("returns list of OS strings", async () => {
    const mockData = ["linux", "windows", "mac"];
    mockAdoptiumGet.mockResolvedValue({ data: mockData, error: null });

    const result = await fetchOperatingSystems();
    expect(result).toEqual(mockData);
  });

  it("returns empty array when data is null", async () => {
    mockAdoptiumGet.mockResolvedValue({ data: null, error: null });

    const result = await fetchOperatingSystems();
    expect(result).toEqual([]);
  });

  it("throws on API error", async () => {
    mockAdoptiumGet.mockResolvedValue({
      data: null,
      error: { message: "error" },
    });

    await expect(fetchOperatingSystems()).rejects.toEqual({ message: "error" });
  });

  it("forwards AbortSignal to the request", async () => {
    mockAdoptiumGet.mockResolvedValue({ data: [], error: null });
    const signal = new AbortController().signal;

    await fetchOperatingSystems(signal);
    expect(mockAdoptiumGet).toHaveBeenCalledWith(
      "/v3/types/operating_systems",
      expect.objectContaining({ signal }),
    );
  });
});

