// ---------------------------------------------------------------------------
// fetchDownloadStats
// ---------------------------------------------------------------------------
describe("fetchDownloadStats", () => {
  let fetchSpy: ReturnType<typeof vi.spyOn>;

  beforeEach(() => {
    fetchSpy = vi.spyOn(global, "fetch");
  });

  afterEach(() => {
    fetchSpy.mockRestore();
  });

  it("returns parsed JSON on success", async () => {
    const mockStats = { total: 1234 };
    fetchSpy.mockResolvedValue({
      ok: true,
      json: () => Promise.resolve(mockStats),
    } as Response);

    const result = await fetchDownloadStats("jdk-21+35");
    expect(result).toEqual(mockStats);
  });

  it("returns null when response is not ok", async () => {
    fetchSpy.mockResolvedValue({ ok: false } as Response);

    const result = await fetchDownloadStats("jdk-21+35");
    expect(result).toBeNull();
  });

  it("appends subpath to URL when provided", async () => {
    fetchSpy.mockResolvedValue({
      ok: true,
      json: () => Promise.resolve({}),
    } as Response);

    await fetchDownloadStats("jdk-21+35", "linux");
    expect(fetchSpy).toHaveBeenCalledWith(
      "https://api.adoptium.net/stats/downloads/total/jdk-21+35/linux",
    );
  });

  it("omits subpath when not provided", async () => {
    fetchSpy.mockResolvedValue({
      ok: true,
      json: () => Promise.resolve({}),
    } as Response);

    await fetchDownloadStats("jdk-21+35");
    expect(fetchSpy).toHaveBeenCalledWith(
      "https://api.adoptium.net/stats/downloads/total/jdk-21+35",
    );
  });
});

