describe("fetchMarketplaceReleases", () => {
  it("returns data on success", async () => {
    const mockData = [{ release_name: "jdk-21+35" }];
    mockMarketplaceGet.mockResolvedValue({ data: mockData, error: null });

    const result = await fetchMarketplaceReleases({ version: 21, vendors: [] });
    expect(result).toEqual(mockData);
  });

  it("returns null when data is null", async () => {
    mockMarketplaceGet.mockResolvedValue({ data: null, error: null });

    const result = await fetchMarketplaceReleases({ version: 21, vendors: [] });
    expect(result).toBeNull();
  });

  it("returns null on API error", async () => {
    mockMarketplaceGet.mockResolvedValue({
      data: null,
      error: { message: "error" },
    });

    const result = await fetchMarketplaceReleases({ version: 21, vendors: [] });
    expect(result).toBeNull();
  });

  it("returns null when request throws", async () => {
    mockMarketplaceGet.mockRejectedValue(new Error("network error"));

    const result = await fetchMarketplaceReleases({ version: 21, vendors: [] });
    expect(result).toBeNull();
  });

  it("includes os in query when provided", async () => {
    mockMarketplaceGet.mockResolvedValue({ data: [], error: null });

    await fetchMarketplaceReleases({ version: 21, os: "linux", vendors: [] });
    const callArgs = mockMarketplaceGet.mock.calls[0][1];
    expect(callArgs.params.query.os).toEqual(["linux"]);
  });

  it("includes architecture in query when provided", async () => {
    mockMarketplaceGet.mockResolvedValue({ data: [], error: null });

    await fetchMarketplaceReleases({
      version: 21,
      architecture: "x64",
      vendors: [],
    });
    const callArgs = mockMarketplaceGet.mock.calls[0][1];
    expect(callArgs.params.query.architecture).toEqual(["x64"]);
  });

  it("includes image_type in query when package_type is provided", async () => {
    mockMarketplaceGet.mockResolvedValue({ data: [], error: null });

    await fetchMarketplaceReleases({
      version: 21,
      package_type: "jdk",
      vendors: [],
    });
    const callArgs = mockMarketplaceGet.mock.calls[0][1];
    expect(callArgs.params.query.image_type).toEqual(["jdk"]);
  });

  it("omits os from query when not provided", async () => {
    mockMarketplaceGet.mockResolvedValue({ data: [], error: null });

    await fetchMarketplaceReleases({ version: 21, vendors: [] });
    const callArgs = mockMarketplaceGet.mock.calls[0][1];
    expect(callArgs.params.query.os).toBeUndefined();
  });
});
